// src/components/EditEvent.js

import React, { useState, useEffect } from 'react';

const EditEvent = () => {
  const [event, setEvent] = useState({
    event_id: 0, // 初期値は適切な値に変更する
    event_name: '',
    event_state: '',
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setEvent((prevEvent) => ({ ...prevEvent, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const response = await fetch('http://localhost:8000/event/edit', {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(event),
      });

      if (response.ok) {
        console.log('Event updated successfully!');
        // ここで成功時の処理を追加する（例: リダイレクトなど）
      } else {
        console.error('Failed to update event');
      }
    } catch (error) {
      console.error('Error:', error);
    }
  };

  useEffect(() => {
    // ページがマウントされたときに初期データを取得するなどの処理を追加
  }, []); 

  return (
    <div>
      <h2>Edit Event</h2>
      <form onSubmit={handleSubmit}>
        <label>
          Event ID:
          <input
            type="number"
            name="event_id"
            value={event.event_id}
            onChange={handleChange}
            readOnly // ユーザに変更させない場合
          />
        </label>
        <br />
        <label>
          Event Name:
          <input
            type="text"
            name="event_name"
            value={event.event_name}
            onChange={handleChange}
          />
        </label>
        <br />
        <label>
          Event State:
          <input
            type="text"
            name="event_state"
            value={event.event_state}
            onChange={handleChange}
          />
        </label>
        <br />
        <button type="submit">Update Event</button>
      </form>
    </div>
  );
};

export default EditEvent;
